 66→// generateRSAPEM creates a fresh RSA key pair and returns the PEM-encoded public key.
 67→func generateRSAPEM(t *testing.T) string {
 68→	t.Helper()
 69→	key, err := rsa.GenerateKey(rand.Reader, 2048)
 70→	if err != nil {
 71→		t.Fatalf("generate RSA key: %v", err)
 72→	}
 73→	pubBytes, err := x509.MarshalPKIXPublicKey(&key.PublicKey)
 74→	if err != nil {
 75→		t.Fatalf("marshal RSA public key: %v", err)
 76→	}
 77→	return string(pem.EncodeToMemory(&pem.Block{Type: "PUBLIC KEY", Bytes: pubBytes}))
 78→}
