186→func TestRouteProtection(t *testing.T) {
187→	t.Parallel()
188→
189→	// Use a validator that rejects all tokens — lets us test both anonymous
190→	// pass-through (OptionalAuth) and mandatory rejection (Auth).
191→	failValidator := &stubValidator{err: http.ErrNotSupported}
192→
193→	cfg := testConfig(func(c *config.Config) { c.MCPEnabled = true })
194→	h := router.New(testDeps(cfg, failValidator))
195→
196→	tests := []struct {
197→		name       string
198→		method     string
199→		path       string
200→		authHeader string
201→		wantStatus int    // exact match; 0 means "not 401"
202→		wantNot    int    // status must NOT be this
203→		checkWWW   bool   // verify WWW-Authenticate header
204→	}{
205→		{
206→			name:    "graphql anonymous allowed",
207→			method:  "POST",
208→			path:    "/graphql",
209→			wantNot: http.StatusUnauthorized,
210→		},
211→		{
212→			name:       "graphql invalid token rejected",
213→			method:     "POST",
214→			path:       "/graphql",
215→			authHeader: "Bearer bad-token",
216→			wantStatus: http.StatusUnauthorized,
217→		},
218→		{
219→			name:    "export anonymous allowed",
220→			method:  "GET",
221→			path:    "/api/export/csv",
222→			wantNot: http.StatusUnauthorized,
223→		},
224→		{
225→			name:       "export invalid token rejected",
226→			method:     "GET",
227→			path:       "/api/export/csv",
228→			authHeader: "Bearer bad-token",
229→			wantStatus: http.StatusUnauthorized,
230→		},
231→		{
232→			name:       "mcp unauthenticated rejected",
233→			method:     "POST",
234→			path:       "/mcp/message",
235→			wantStatus: http.StatusUnauthorized,
236→			checkWWW:   true,
237→		},
238→		{
239→			name:       "mcp invalid token rejected",
240→			method:     "POST",
241→			path:       "/mcp/message",
242→			authHeader: "Bearer bad-token",
243→			wantStatus: http.StatusUnauthorized,
244→			checkWWW:   true,
245→		},
246→		{
247→			name:       "well-known no auth required",
248→			method:     "GET",
249→			path:       "/.well-known/oauth-protected-resource",
250→			wantStatus: http.StatusOK,
251→		},
252→	}
253→	for _, tt := range tests {
254→		t.Run(tt.name, func(t *testing.T) {
255→			t.Parallel()
256→			req := httptest.NewRequest(tt.method, tt.path, nil)
257→			if tt.authHeader != "" {
258→				req.Header.Set("Authorization", tt.authHeader)
259→			}
260→			rr := httptest.NewRecorder()
261→			h.ServeHTTP(rr, req)
262→
263→			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
264→				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
265→			}
266→			if tt.wantNot != 0 && rr.Code == tt.wantNot {
267→				t.Errorf("status = %d, must not be %d", rr.Code, tt.wantNot)
268→			}
269→			if tt.checkWWW {
270→				wwwAuth := rr.Header().Get("WWW-Authenticate")
271→				if !strings.Contains(wwwAuth, "Bearer") {
272→					t.Errorf("WWW-Authenticate = %q, want Bearer", wwwAuth)
273→				}
274→				if !strings.Contains(wwwAuth, `resource_metadata="/.well-known/oauth-protected-resource"`) {
275→					t.Errorf("WWW-Authenticate = %q, want resource_metadata", wwwAuth)
276→				}
277→			}
278→		})
279→	}
280→}
